Create the `ClaudeCodeRuntime` class by renaming/extending the current `AgentManager` to implement the `AgentRuntime` interface. The class encapsulates TranscriptReader, SessionBroadcaster, SessionLockManager, and CommandRegistryService internally.

**File to create:** `apps/server/src/services/runtimes/claude-code/claude-code-runtime.ts`

This file is essentially the current `agent-manager.ts` with these additions:

1. `implements AgentRuntime` on the class declaration
2. Internal ownership of `TranscriptReader`, `SessionBroadcaster`, `CommandRegistryService`
3. New delegation methods: `listSessions()`, `getSession()`, `getMessageHistory()`, `getSessionTasks()`, `getSessionETag()`, `readFromOffset()`, `watchSession()`, `getCommands()`
4. `getCapabilities()` returning static Claude Code capabilities
5. `getInternalSessionId()` (renamed from `getSdkSessionId()`)
6. Keep the `getSdkSessionId()` method as an alias for backward compatibility

**Key implementation details:**

```typescript
import type { AgentRuntime, RuntimeCapabilities, SessionOpts, MessageOpts } from '@dorkos/shared/agent-runtime';
import { TranscriptReader } from './transcript-reader.js';
import { SessionBroadcaster } from './session-broadcaster.js';
import { CommandRegistryService } from './command-registry.js';
import { SessionLockManager } from './session-lock.js';
// ... other existing imports from agent-manager.ts

export class ClaudeCodeRuntime implements AgentRuntime {
  readonly type = 'claude-code' as const;

  // Internal services (previously standalone singletons)
  private readonly transcriptReader: TranscriptReader;
  private readonly broadcaster: SessionBroadcaster;
  private commandRegistry: CommandRegistryService | null = null;

  // ... all existing AgentManager fields (sessions Map, lockManager, etc.)

  constructor(cwd?: string) {
    // ... same as current AgentManager constructor
    this.transcriptReader = new TranscriptReader();
    this.broadcaster = new SessionBroadcaster(this.transcriptReader);
  }

  getCapabilities(): RuntimeCapabilities {
    return {
      type: 'claude-code',
      supportsPermissionModes: true,
      supportedPermissionModes: ['default', 'plan', 'acceptEdits', 'bypassPermissions'],
      supportsToolApproval: true,
      supportsCostTracking: true,
      supportsResume: true,
      supportsMcp: true,
      supportsQuestionPrompt: true,
    };
  }

  // --- Session queries delegate to TranscriptReader ---
  async listSessions(projectDir: string): Promise<Session[]> {
    return this.transcriptReader.listSessions(projectDir);
  }

  async getSession(projectDir: string, sessionId: string): Promise<Session | null> {
    return this.transcriptReader.getSession(projectDir, sessionId);
  }

  async getMessageHistory(projectDir: string, sessionId: string): Promise<HistoryMessage[]> {
    return this.transcriptReader.readTranscript(projectDir, sessionId);
  }

  async getSessionTasks(projectDir: string, sessionId: string): Promise<TaskItem[]> {
    return this.transcriptReader.readTasks(projectDir, sessionId);
  }

  async getSessionETag(projectDir: string, sessionId: string): Promise<string | null> {
    return this.transcriptReader.getTranscriptETag(projectDir, sessionId);
  }

  async readFromOffset(projectDir: string, sessionId: string, offset: number) {
    return this.transcriptReader.readFromOffset(projectDir, sessionId, offset);
  }

  // --- Session sync delegates to SessionBroadcaster ---
  watchSession(
    sessionId: string,
    projectDir: string,
    _callback: (event: StreamEvent) => void,
    _clientId?: string
  ): () => void {
    // Not directly used by routes — routes use registerClient/deregisterClient on the broadcaster.
    // This method exists to satisfy the AgentRuntime interface.
    // Routes will access the internal broadcaster via getSessionBroadcaster().
    return () => {};
  }

  // Expose internal services for routes that need direct access during migration
  getTranscriptReader(): TranscriptReader { return this.transcriptReader; }
  getSessionBroadcaster(): SessionBroadcaster { return this.broadcaster; }

  // --- Commands ---
  async getCommands(forceRefresh?: boolean): Promise<CommandRegistry> {
    if (!this.commandRegistry) {
      this.commandRegistry = new CommandRegistryService(this.cwd);
    }
    return this.commandRegistry.getCommands(forceRefresh);
  }

  // Renamed from getSdkSessionId for the interface
  getInternalSessionId(sessionId: string): string | undefined {
    return this.findSession(sessionId)?.sdkSessionId;
  }

  // Keep backward-compatible alias
  getSdkSessionId(sessionId: string): string | undefined {
    return this.getInternalSessionId(sessionId);
  }

  // ... all existing AgentManager methods remain unchanged
}
```

