Create a new capabilities route that exposes runtime metadata to the client. This enables the client to detect what features are available based on the active runtime.

**Create file:** `apps/server/src/routes/capabilities.ts`

```typescript
import { Router } from 'express';
import { runtimeRegistry } from '../services/core/runtime-registry.js';

const router = Router();

/**
 * GET /api/capabilities — returns capabilities for all registered runtimes.
 *
 * Response: {
 *   capabilities: Record<string, RuntimeCapabilities>,
 *   defaultRuntime: string
 * }
 */
router.get('/', (_req, res) => {
  const capabilities = runtimeRegistry.getAllCapabilities();
  const defaultRuntime = runtimeRegistry.getDefaultType();
  res.json({ capabilities, defaultRuntime });
});

export default router;
```

