Create a new client entity hook for runtime capabilities and update UI components to use capability-driven feature detection.

**Create hook:** `apps/client/src/layers/entities/runtime/model/use-runtime-capabilities.ts`

```typescript
import { useQuery } from '@tanstack/react-query';
import { useTransport } from '@/layers/shared/model';
import type { RuntimeCapabilities } from '@dorkos/shared/agent-runtime';

/**
 * Fetch runtime capabilities from the server.
 *
 * Capabilities are static for the lifetime of a session, so we use
 * `staleTime: Infinity` to avoid unnecessary refetches.
 */
export function useRuntimeCapabilities() {
  const transport = useTransport();
  return useQuery({
    queryKey: ['capabilities'],
    queryFn: () => transport.getCapabilities(),
    staleTime: Infinity,
  });
}

/** Get the default runtime's capabilities. */
export function useDefaultCapabilities(): RuntimeCapabilities | undefined {
  const { data } = useRuntimeCapabilities();
  if (!data) return undefined;
  return data.capabilities[data.defaultRuntime];
}
```

